import csv

with open("scores.csv", "r") as file:
    reader = csv.DictReader(file)
    for row in reader:
        name = row["name"].strip()
        try:
            score = int(row["score"].strip())
            print(f"{name}: {score}")
        except ValueError:
            print(f"Skipped: {name}")
